demos.desktop:
render(() => {
    const getChildStyle = (bgColor) => ({
        height: 80,
        textAlign: 'center',
        lineHeight: '80px',
        fontSize: 40,
        fontWeight: 700,
        color: 'var(--color-light-text-tertiary)',
        background: `var(${bgColor})`,
    });
    return (
        <div style={{ height: 240, margin: 'var(--gap-20-neg)' }}>
            <Scrollbar style={{ height: '100%' }} autoHide={false}>
                {new Array(51).fill(null).map((_, idx) => {
                    const style = getChildStyle(
                        idx % 2 === 0 ? '--color-light-neutral-200' : '--color-light-base-bg-secondary',
                    );
                    return (
                        <div key={idx} style={style}>
                            {idx + 1}
                        </div>
                    );
                })}
            </Scrollbar>
        </div>
    );
});
